import{_ as e,o as l,c as i,ae as r}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"AI 幻觉的成因解析与缓解：从采样到系统防线","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/hallucination.md","filePath":"ai-tutorial/hallucination.md"}'),t={name:"ai-tutorial/hallucination.md"};function o(h,a,n,p,u,d){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="ai-幻觉的成因解析与缓解-从采样到系统防线" tabindex="-1">AI 幻觉的成因解析与缓解：从采样到系统防线 <a class="header-anchor" href="#ai-幻觉的成因解析与缓解-从采样到系统防线" aria-label="Permalink to &quot;AI 幻觉的成因解析与缓解：从采样到系统防线&quot;">​</a></h1><blockquote><p>很多人第一次见识 AI 幻觉，都会有一种非常微妙的感受：它不是在随便乱说，而是在一本正经地乱说。 也正因为如此，幻觉才格外危险。它不像普通程序报错那样明显，它往往语言流畅、逻辑通顺，甚至还带着一点让人放松警惕的自信。要真正处理这个问题，靠的不是一句“请不要胡编”，而是先看清它到底是从哪一层冒出来的。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>幻觉为什么是生成式模型的天然风险</li><li>温度、采样、知识缺失和上下文噪声如何影响幻觉</li><li>如何从 Prompt、检索、结构化校验和系统流程四层缓解风险</li></ul></div><h2 id="_1-幻觉不是-bug-而是概率生成的副作用" tabindex="-1">1. 幻觉不是 bug，而是概率生成的副作用 <a class="header-anchor" href="#_1-幻觉不是-bug-而是概率生成的副作用" aria-label="Permalink to &quot;1. 幻觉不是 bug，而是概率生成的副作用&quot;">​</a></h2><p>大模型生成下一个 Token 的方式，本质上是在候选概率分布中做选择。只要系统不是直接检索事实库，而是在“根据上下文生成最可能的下一个词”，它就天然可能：</p><ul><li>补全不存在的事实</li><li>编造看似合理的引用</li><li>给出语言流畅但证据不足的结论</li></ul><p>所以幻觉不是一种特殊故障，而是生成式系统的结构性风险。</p><h2 id="_2-幻觉最常见的四个来源" tabindex="-1">2. 幻觉最常见的四个来源 <a class="header-anchor" href="#_2-幻觉最常见的四个来源" aria-label="Permalink to &quot;2. 幻觉最常见的四个来源&quot;">​</a></h2><h3 id="_2-1-模型缺少关键事实" tabindex="-1">2.1 模型缺少关键事实 <a class="header-anchor" href="#_2-1-模型缺少关键事实" aria-label="Permalink to &quot;2.1 模型缺少关键事实&quot;">​</a></h3><p>如果问题需要外部知识，而上下文里没有提供，模型仍然会倾向于给出一个“尽量像答案的答案”。</p><h3 id="_2-2-上下文噪声过多" tabindex="-1">2.2 上下文噪声过多 <a class="header-anchor" href="#_2-2-上下文噪声过多" aria-label="Permalink to &quot;2.2 上下文噪声过多&quot;">​</a></h3><p>当检索结果杂乱、候选太长、提示词不聚焦时，模型可能在噪声中抓住错误线索并继续扩写。</p><h3 id="_2-3-采样带来的随机性" tabindex="-1">2.3 采样带来的随机性 <a class="header-anchor" href="#_2-3-采样带来的随机性" aria-label="Permalink to &quot;2.3 采样带来的随机性&quot;">​</a></h3><p>更高的温度、更开放的采样空间，会增加表达多样性，也会放大不稳定性。</p><h3 id="_2-4-任务本身缺乏可验证标准" tabindex="-1">2.4 任务本身缺乏可验证标准 <a class="header-anchor" href="#_2-4-任务本身缺乏可验证标准" aria-label="Permalink to &quot;2.4 任务本身缺乏可验证标准&quot;">​</a></h3><p>如果问题没有明确边界，比如“帮我全面判断这个合同是否存在一切风险”，模型很容易在大范围模糊任务中自信扩展。</p><h2 id="_3-温度和-top-p-的作用-不是简单的-越低越准" tabindex="-1">3. 温度和 Top-p 的作用，不是简单的“越低越准” <a class="header-anchor" href="#_3-温度和-top-p-的作用-不是简单的-越低越准" aria-label="Permalink to &quot;3. 温度和 Top-p 的作用，不是简单的“越低越准”&quot;">​</a></h2><h3 id="_3-1-temperature" tabindex="-1">3.1 Temperature <a class="header-anchor" href="#_3-1-temperature" aria-label="Permalink to &quot;3.1 Temperature&quot;">​</a></h3><p>Temperature 越高，输出越发散；越低，输出越保守。</p><p>这通常意味着：</p><ul><li>创意写作适合稍高温度</li><li>信息抽取、分类、结构化输出更适合低温度</li></ul><p>但要注意，温度低不等于绝对正确。它只能减少随机性，不能凭空补足缺失的事实。</p><h3 id="_3-2-top-p" tabindex="-1">3.2 Top-p <a class="header-anchor" href="#_3-2-top-p" aria-label="Permalink to &quot;3.2 Top-p&quot;">​</a></h3><p>Top-p 通过截断低概率候选来限制采样空间。它和温度一样，影响的是“怎么选”，而不是“事实从哪里来”。</p><p>所以当问题根源是知识缺失时，继续调采样参数通常治标不治本。</p><h2 id="_4-生产系统里的四层防线" tabindex="-1">4. 生产系统里的四层防线 <a class="header-anchor" href="#_4-生产系统里的四层防线" aria-label="Permalink to &quot;4. 生产系统里的四层防线&quot;">​</a></h2><h3 id="_4-1-prompt-层-让模型知道什么时候该保守" tabindex="-1">4.1 Prompt 层：让模型知道什么时候该保守 <a class="header-anchor" href="#_4-1-prompt-层-让模型知道什么时候该保守" aria-label="Permalink to &quot;4.1 Prompt 层：让模型知道什么时候该保守&quot;">​</a></h3><p>一个实用原则是明确告诉模型：</p><ul><li>如果证据不足，要说“不确定”</li><li>不要伪造来源</li><li>如果需要外部事实，应优先使用提供的资料</li></ul><p>这类提示不会消灭幻觉，但能明显改善“瞎编还很自信”的情况。</p><h3 id="_4-2-检索层-把事实先送到位" tabindex="-1">4.2 检索层：把事实先送到位 <a class="header-anchor" href="#_4-2-检索层-把事实先送到位" aria-label="Permalink to &quot;4.2 检索层：把事实先送到位&quot;">​</a></h3><p>如果问题依赖企业知识或实时信息，最有效的方式通常不是继续打磨提示词，而是：</p><ul><li>用 RAG 补足静态事实</li><li>用工具调用补足实时数据</li></ul><p>很多看起来是“模型胡说八道”的问题，根本原因其实是系统没有提供足够事实。</p><h3 id="_4-3-输出层-把回答变成可校验结构" tabindex="-1">4.3 输出层：把回答变成可校验结构 <a class="header-anchor" href="#_4-3-输出层-把回答变成可校验结构" aria-label="Permalink to &quot;4.3 输出层：把回答变成可校验结构&quot;">​</a></h3><p>结构化输出能帮助你在系统层面识别很多问题：</p><ul><li>字段缺失</li><li>枚举越界</li><li>数值格式错误</li><li>引用来源为空</li></ul><p>这意味着即便模型没有完全“更聪明”，系统仍然可以拦下很多不可用结果。</p><h3 id="_4-4-流程层-把高风险结论从-自动执行-改成-待确认" tabindex="-1">4.4 流程层：把高风险结论从“自动执行”改成“待确认” <a class="header-anchor" href="#_4-4-流程层-把高风险结论从-自动执行-改成-待确认" aria-label="Permalink to &quot;4.4 流程层：把高风险结论从“自动执行”改成“待确认”&quot;">​</a></h3><p>对于下面这些场景，不应该直接相信模型自然语言结论：</p><ul><li>法务判断</li><li>医疗建议</li><li>财务动作</li><li>人事处罚</li></ul><p>更稳的做法是把模型输出变成“待审核建议”，而不是“直接执行结果”。</p><h2 id="_5-一个更实用的判断框架" tabindex="-1">5. 一个更实用的判断框架 <a class="header-anchor" href="#_5-一个更实用的判断框架" aria-label="Permalink to &quot;5. 一个更实用的判断框架&quot;">​</a></h2><p>如果你遇到幻觉问题，可以先问：</p><ol><li>是没有事实，还是没有正确召回事实？</li><li>是输出太发散，还是任务本身定义模糊？</li><li>是自然语言回答不可控，还是缺少结构化校验？</li><li>是普通误差，还是已经进入高风险业务场景？</li></ol><p>这四个问题能帮助你判断该调 Prompt、调检索、加校验，还是改业务流程。</p><h2 id="_6-常见反模式" tabindex="-1">6. 常见反模式 <a class="header-anchor" href="#_6-常见反模式" aria-label="Permalink to &quot;6. 常见反模式&quot;">​</a></h2><h3 id="_6-1-只靠一句-不要幻觉" tabindex="-1">6.1 只靠一句“不要幻觉” <a class="header-anchor" href="#_6-1-只靠一句-不要幻觉" aria-label="Permalink to &quot;6.1 只靠一句“不要幻觉”&quot;">​</a></h3><p>这种提示几乎没有系统性约束力。</p><h3 id="_6-2-把所有希望都寄托在低温度" tabindex="-1">6.2 把所有希望都寄托在低温度 <a class="header-anchor" href="#_6-2-把所有希望都寄托在低温度" aria-label="Permalink to &quot;6.2 把所有希望都寄托在低温度&quot;">​</a></h3><p>低温度可以更稳，但不能创造事实。</p><h3 id="_6-3-不给引用来源" tabindex="-1">6.3 不给引用来源 <a class="header-anchor" href="#_6-3-不给引用来源" aria-label="Permalink to &quot;6.3 不给引用来源&quot;">​</a></h3><p>没有来源展示，用户和开发者都无法判断结论依据。</p><h3 id="_6-4-让模型在高风险场景直接落动作" tabindex="-1">6.4 让模型在高风险场景直接落动作 <a class="header-anchor" href="#_6-4-让模型在高风险场景直接落动作" aria-label="Permalink to &quot;6.4 让模型在高风险场景直接落动作&quot;">​</a></h3><p>这不是“大胆”，而是把不确定性直接传给业务系统。</p><h2 id="_7-小结" tabindex="-1">7. 小结 <a class="header-anchor" href="#_7-小结" aria-label="Permalink to &quot;7. 小结&quot;">​</a></h2><p>幻觉不是一个可以靠单一技巧彻底消灭的问题。更现实的做法是分层治理：</p><ul><li>Prompt 层降低无依据扩写</li><li>检索和工具层补足事实</li><li>结构化输出层拦截不合规结果</li><li>业务流程层控制高风险动作</li></ul><p>当你把幻觉看成系统问题，而不是模型性格问题，解决思路就会清晰得多。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI: Prompt engineering</a></li><li><a href="https://arxiv.org/abs/2307.03172" target="_blank" rel="noreferrer">Lost in the Middle: How Language Models Use Long Contexts</a></li><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li>延伸阅读：<a href="./rag-intro.html">初探 RAG 架构</a></li></ul>',61)])])}const _=e(t,[["render",o]]);export{c as __pageData,_ as default};
